# cfr_calculator.py — correlate incidents with deployments
from datetime import datetime, timedelta
from typing import List, Dict

def calculate_cfr(
    deployments: List[Dict],
    incidents: List[Dict],
    correlation_window_hours: int = 24
) -> Dict:
    window = timedelta(hours=correlation_window_hours)
    failed_deployments = set()

    for incident in incidents:
        incident_time = datetime.fromisoformat(incident["timestamp"])
        service = incident["service"]
        for deploy in deployments:
            if deploy["service"] != service:
                continue
            deploy_time = datetime.fromisoformat(deploy["timestamp"])
            if 0 <= (incident_time - deploy_time).total_seconds() <= window.total_seconds():
                failed_deployments.add((deploy["sha"], deploy["timestamp"]))

    total = len(deployments)
    failed = len(failed_deployments)
    return {
        "total_deployments": total,
        "failed_deployments": failed,
        "change_failure_rate": (failed / total * 100) if total > 0 else 0,
    }

# mttr_calculator.py from datetime import datetime from typing import List, Dict import statistics
def calculate_mttr(incidents: List[Dict]) -> Dict: resolution_times = [] for incident in incidents: if not incident.get("resolved_at"): continue created = datetime.fromisoformat(incident["created_at"]) resolved = datetime.fromisoformat(incident["resolved_at"]) resolution_times.append((resolved - created).total_seconds() / 60)
return { "total_incidents": len(incidents), "resolved_incidents": len(resolution_times), "mttr_minutes": statistics.mean(resolution_times) if resolution_times else 0, "mttr_median_minutes": statistics.median(resolution_times) if resolution_times else 0, }
